script:
code = frappe.utils.generate_hash("token")[:8]

referral_exists = frappe.db.exists("Referral",doc.name)
if not referral_exists:

    ref= frappe.new_doc("Referral")
    #ref.name = code
    ref.code = code
    ref.user = doc.name
    code_r =frappe.form_dict.get('code')
    if code_r:
        ref.referred_user = 1;
        ref.referred_by_code = frappe.form.dict.code;
    ref.db_insert()

else:
    pass
